SELECT total_emission_inc_lucf
FROM total_emissions
WHERE year = 2017;

SELECT AVG(per_capita_emission) AS average_per_capita_emission
FROM per_capita_emissions
WHERE year = 2017;

SELECT SUM(total_emission_ex_lucf) AS total_ex_lucf
FROM total_emissions
WHERE year = 2018;

SELECT AVG(total_emission_ex_lucf) AS average_emission_ex_lucf
FROM total_emissions
WHERE year = 2017;
